  color: #fff !important;
  border-radius: 100px;
  padding: 0.5rem 1.2rem;
  line-height: 1;
  overflow: visible !important;
}

/* 二级菜单基础样式 */
#nav #menus .menus_item .menus_item_child {
  position: absolute !important;
  top: calc(100% + 10px) !important;
  left: 50%;
  transform: translateX(-50%) translateY(-12px) scaleY(0.6);
  transform-origin: top center;
  opacity: 0;
  pointer-events: none;
  transition: opacity .3s ease 0.15s, transform .3s cubic-bezier(0.6, -0.28, 0.74, 0.05) 0.15s;
  padding: 10px 6px;
  border-radius: 20px;
  background: #425AEF;
  white-space: nowrap;
  z-index: 999;
}

/* 桥接伪元素：连接一级和二级菜单，让 gooey 能融合 */
#nav #menus .menus_item .menus_item_child::before {
  content: "";
  position: absolute;
  top: -14px;
  left: 50%;
  transform: translateX(-50%);
  width: 20px;
  height: 18px;
  background: #425AEF;
  border-radius: 50%;
}

/* hover 时显示 - 弹性弹出动画 */
#nav #menus .menus_item:hover > .menus_item_child {
  opacity: 1;
  pointer-events: auto;
  transform: translateX(-50%) translateY(0) scaleY(1);
