/* ========== 封面图缺失兜底（CSS-only）========== */
/* 当文章没设置 cover 时，模板输出 src="/"，浏览器会请求根路径失败。
   这里隐藏失效的 img，用容器 background 兜底显示默认图。
   配合 articleSort.pug 的模板改动：cover 空时直接输出 default.avif。 */
#archive .article-sort-item-img {
  background-color: #f0f2f5;
}

#archive .article-sort-item-img img[src="/"],
#archive .article-sort-item-img img:not([src]) {
  opacity: 0;
}

/* 用 :has() 选中"没有有效封面"的封面容器，铺默认图 */
#archive .article-sort-item-img:has(img[src="/"]),
#archive .article-sort-item-img:has(img:not([src])) {
  background-image: url("/img/default.avif");
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* 顶荐位（首页）：同问题 */
.post_cover:has(img.post_bg[src="/"]) {
  background-image: url("/img/default.avif");
  background-size: cover;
  background-position: center;
}

.post_cover:has(img.post_bg[src="/"]) img.post_bg {
  opacity: 0;
}

/* ============================================
 * ============ 1. 首页文章卡片美化 ============
 * ============================================ */

/* 卡片整体：更柔的阴影 + 边框 + 悬浮动效 */
#recent-posts .recent-post-item {
  background: var(--efu-card-bg);
  border: 1px solid var(--efu-card-border);
  border-radius: 16px !important;
  overflow: hidden;
  box-shadow: 0 2px 14px rgba(0, 0, 0, 0.04);
  transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1),
              box-shadow 0.35s ease,
              border-color 0.35s ease;
  position: relative;
}

#recent-posts .recent-post-item::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 16px;
  background: linear-gradient(135deg, rgba(66, 90, 239, 0.05), rgba(236, 72, 153, 0.05));
  opacity: 0;
  transition: opacity 0.35s ease;
  pointer-events: none;
  z-index: 0;
}

#recent-posts .recent-post-item:hover {
