  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

#recent-posts .recent-post-item:hover .recent-post-info .article-title {
  background: linear-gradient(135deg, #425AEF, #8B5CF6, #EC4899);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  color: transparent;
}

/* 摘要/内容：行高 + 颜色 */
#recent-posts .recent-post-item .recent-post-info .content {
  color: var(--efu-secondtext);
  line-height: 1.7;
  font-size: 0.92rem;
}

/* 标签：药丸样式 */
#recent-posts .recent-post-item .article-meta__tags {
  background: rgba(66, 90, 239, 0.08) !important;
  padding: 0.2rem 0.6rem !important;
  border-radius: 100px !important;
  margin-right: 0.3rem !important;
  border: 1px solid transparent;
  transition: all 0.25s ease;
  color: var(--efu-secondtext) !important;
  font-weight: 500 !important;
}

#recent-posts .recent-post-item .article-meta__tags:hover {
  background: rgba(66, 90, 239, 0.15) !important;
  border-color: rgba(66, 90, 239, 0.3) !important;
  color: var(--efu-theme) !important;
  transform: translateY(-1px);
}

/* meta 角标：置顶/分类/新文章 */
#recent-posts .recent-post-item .recent-post-info-top-tips .original,
#recent-posts .recent-post-item .recent-post-info-top-tips .sticky {
  background: rgba(66, 90, 239, 0.08) !important;
  color: var(--efu-theme) !important;
  border-radius: 6px !important;
  padding: 0.15rem 0.55rem !important;
  font-size: 0.72rem !important;
  font-weight: 600 !important;
  border: 1px solid rgba(66, 90, 239, 0.15);
  transition: all 0.25s ease;
}

#recent-posts .recent-post-item .recent-post-info-top-tips .original:hover,
#recent-posts .recent-post-item .recent-post-info-top-tips .sticky:hover {
  background: rgba(66, 90, 239, 0.15) !important;
  border-color: rgba(66, 90, 239, 0.3) !important;
}

#recent-posts .recent-post-item .recent-post-info-top-tips .unvisited-post {
  color: var(--efu-secondtext) !important;
  font-size: 0.78rem !important;
  transition: color 0.25s ease;
}

#recent-posts .recent-post-item .recent-post-info-top-tips .unvisited-post:hover {
  color: var(--efu-theme) !important;
}

/* 顶荐位大图：左下角渐变文字 + 圆角 */
#home_top .top-post-group .top-post-item {
  border-radius: 14px !important;
  overflow: hidden;
  transition: transform 0.35s ease, box-shadow 0.35s ease;
}

#home_top .top-post-group .top-post-item:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 30px rgba(66, 90, 239, 0.15);
}

#home_top .top-post-group .top-post-info .article-title {
  font-weight: 700 !important;
  transition: color 0.3s ease;
}

#home_top .top-post-group .top-post-item:hover .top-post-info .article-title {
  color: var(--efu-theme) !important;
}

/* ============================================
 * ============ 2. 文章详情页排版 ============
 * ============================================ */

/* 文章内容区：稍大行高 + 段落间距 */
.article-container.post-content {
  font-size: 16px;
  line-height: 1.85;
}

.article-container.post-content p {
  margin: 0.85em 0;
  letter-spacing: 0.3px;
}

/* 标题层级：渐变色条 + 字号 + 间距 */
.article-container.post-content h1,
.article-container.post-content h2,
.article-container.post-content h3,
.article-container.post-content h4,
.article-container.post-content h5,
.article-container.post-content h6 {
  position: relative;
  font-weight: 700 !important;
  color: var(--efu-fontcolor) !important;
  transition: all 0.3s ease;
}

.article-container.post-content h1 {
  font-size: 1.75rem !important;
  margin: 1.5em 0 0.8em;
}

.article-container.post-content h2 {
  font-size: 1.45rem !important;
  margin: 1.6em 0 0.8em;
  padding: 0 0 0 0.9rem !important;
  padding-top: 0.5em !important;
  border-top: 1px dashed rgba(66, 90, 239, 0.2) !important;
}

.article-container.post-content h3 {
  font-size: 1.22rem !important;
  margin: 1.4em 0 0.7em;
  padding-left: 0.85rem;
}

.article-container.post-content h4 {
  font-size: 1.08rem !important;
  margin: 1.3em 0 0.6em;
  padding-left: 0.8rem;
}

/* h2/h3 左侧色条 */
.article-container.post-content h2::before,
.article-container.post-content h3::before,
.article-container.post-content h4::before {
  content: "";
  position: absolute;
  left: 0;
  top: 0.6em;
  bottom: 0.3em;
  width: 4px;
  border-radius: 2px;
  background: linear-gradient(180deg, #425AEF, #8B5CF6, #EC4899);
  opacity: 0.85;
}

.article-container.post-content h2::before { top: 0.8em; bottom: 0.3em; }
.article-container.post-content h3::before { top: 0.6em; bottom: 0.2em; width: 3.5px; }
.article-container.post-content h4::before { top: 0.5em; bottom: 0.2em; width: 3px; }

/* anchor 链接（小链子图标） */
.article-container.post-content a.headerlink {
  color: var(--efu-theme);
  font-size: 0.85em;
  margin-left: 0.5rem;
  opacity: 0.4;
  transition: opacity 0.2s ease;
  border: none !important;
  font-weight: normal !important;
}

.article-container.post-content h1:hover a.headerlink,
.article-container.post-content h2:hover a.headerlink,
.article-container.post-content h3:hover a.headerlink,
.article-container.post-content h4:hover a.headerlink {
  opacity: 1;
}

/* 段落内联链接：底部渐变线 + hover 反转 */
.article-container.post-content p a:not(.fancybox):not(.headerlink) {
  color: var(--efu-theme) !important;
  text-decoration: none !important;
  border-bottom: 2px solid transparent !important;
  background-image: linear-gradient(90deg, var(--efu-theme), var(--efu-theme)) !important;
  background-size: 0% 2px !important;
  background-repeat: no-repeat !important;
  background-position: 0 100% !important;
  transition: background-size 0.35s ease, color 0.3s ease !important;
  padding: 0 1px;
  font-weight: 600 !important;
}

.article-container.post-content p a:not(.fancybox):not(.headerlink):hover {
  background-size: 100% 2px !important;
}

/* blockquote：渐变左线 + 大引号装饰 + 浅色背景 */
.article-container.post-content blockquote {
  position: relative;
  margin: 1.5em 0;
  padding: 0.9em 1.2em 0.9em 1.6em !important;
  background: linear-gradient(90deg, rgba(66, 90, 239, 0.06), rgba(236, 72, 153, 0.02) 60%, transparent) !important;
  border: none !important;
  border-left: 4px solid #425AEF !important;
  border-radius: 0 10px 10px 0 !important;
  color: var(--efu-fontcolor) !important;
  font-style: normal;
  box-shadow: 0 2px 10px rgba(66, 90, 239, 0.04);
}

.article-container.post-content blockquote::before {
  content: "\201C";
  position: absolute;
  left: 0.2em;
  top: -0.2em;
  font-size: 3.5em;
  line-height: 1;
  color: rgba(66, 90, 239, 0.18);
  font-family: Georgia, serif;
  font-weight: 700;
  pointer-events: none;
}

.article-container.post-content blockquote p {
  margin: 0.3em 0 !important;
  color: var(--efu-fontcolor);
}

/* 列表：marker 主题色 */
.article-container.post-content ul > li::before {
  background: linear-gradient(135deg, #425AEF, #8B5CF6) !important;
  border: none !important;
  box-shadow: 0 0 0 3px rgba(66, 90, 239, 0.1);
}

.article-container.post-content ol > li::before {
  background: linear-gradient(135deg, #425AEF, #8B5CF6) !important;
  color: #fff !important;
  font-weight: 700 !important;
}

.article-container.post-content ul li,
.article-container.post-content ol li {
  margin: 0.4em 0 !important;
  line-height: 1.75;
}

/* 嵌套列表缩进更明显 */
.article-container.post-content ul ul,
.article-container.post-content ol ol,
.article-container.post-content ul ol,
.article-container.post-content ol ul {
  margin: 0.3em 0 0.3em 0.5em !important;
}

/* 表格：渐变表头 + 斑马纹 + hover 高亮 + 圆角 */
.article-container.post-content table {
  width: 100% !important;
  border-collapse: separate !important;
  border-spacing: 0 !important;
  margin: 1.5em 0 !important;
  border-radius: 10px !important;
  overflow: hidden;
  border: 1px solid var(--efu-card-border) !important;
  font-size: 0.92rem;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.04);
}

.article-container.post-content table thead {
  background: linear-gradient(135deg, #425AEF 0%, #8B5CF6 50%, #EC4899 100%) !important;
}

.article-container.post-content table thead th {
  color: #fff !important;
  padding: 0.7em 1em !important;
  font-weight: 600 !important;
  text-align: left;
  border: none !important;
  background: transparent !important;
}

.article-container.post-content table tbody td {
  padding: 0.6em 1em !important;
  border: none !important;
  border-bottom: 1px solid var(--efu-card-border) !important;
  color: var(--efu-fontcolor);
}

.article-container.post-content table tbody tr:nth-child(even) td {
  background: rgba(66, 90, 239, 0.03);
}

.article-container.post-content table tbody tr {
  transition: background 0.2s ease;
}

.article-container.post-content table tbody tr:hover td {
  background: rgba(66, 90, 239, 0.08);
}

.article-container.post-content table tbody tr:last-child td {
  border-bottom: none !important;
}

/* 行内 code：浅色背景 + 主题色 */
.article-container.post-content p code,
.article-container.post-content li code,
.article-container.post-content td code {
  color: #425AEF !important;
  background: rgba(66, 90, 239, 0.08) !important;
  padding: 0.18em 0.5em !important;
  border-radius: 5px !important;
  font-size: 0.88em !important;
  font-weight: 500 !important;
  border: 1px solid rgba(66, 90, 239, 0.12);
  transition: all 0.2s ease;
  font-family: 'JetBrains Mono', Consolas, Menlo, monospace;
}

.article-container.post-content p code:hover,
.article-container.post-content li code:hover,
.article-container.post-content td code:hover {
  background: rgba(66, 90, 239, 0.15) !important;
  color: #fff !important;
  background-image: linear-gradient(135deg, #425AEF, #8B5CF6) !important;
  border-color: transparent;
}

/* 暗色模式下表格和 inline code 适配 */
[data-theme="dark"] .article-container.post-content table tbody tr:nth-child(even) td {
  background: rgba(255, 255, 255, 0.02);
}

[data-theme="dark"] .article-container.post-content p code,
[data-theme="dark"] .article-container.post-content li code,
[data-theme="dark"] .article-container.post-content td code {
  background: rgba(139, 92, 246, 0.15) !important;
  border-color: rgba(139, 92, 246, 0.25);
}

/* hr：渐变线 + 中间小装饰 */
.article-container.post-content hr {
  height: 1px !important;
  background: linear-gradient(90deg, transparent, rgba(66, 90, 239, 0.4), rgba(236, 72, 153, 0.4), transparent) !important;
  border: none !important;
  margin: 2.5em 0 !important;
  position: relative;
}

.article-container.post-content hr::after {
  content: "✦";
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  background: var(--efu-card-bg);
  color: #8B5CF6;
  padding: 0 0.7em;
  font-size: 0.85em;
}

/* 文章内图片：hover 缩放 + 阴影 + 懒加载渐显 */
.article-container.post-content img:not(.post_bg):not(.avatar-img) {
  border-radius: 10px !important;
  transition: transform 0.4s ease, box-shadow 0.4s ease, opacity 0.6s ease;
  cursor: zoom-in;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08);
}

.article-container.post-content img:not(.post_bg):not(.avatar-img):hover {
  transform: scale(1.02);
  box-shadow: 0 8px 28px rgba(66, 90, 239, 0.18);
}

/* ============================================
 * ============ 3. 代码块全套美化 ============
 * ============================================ */

/* figure.highlight 容器：更大圆角 + 阴影 + 边框 */
.article-container figure.highlight,
.article-container pre {
  border-radius: 12px !important;
  margin: 1.2em 0 !important;
  box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
  border: 1px solid var(--efu-card-border);
  transition: box-shadow 0.3s ease, transform 0.3s ease;
  overflow: hidden;
}

.article-container figure.highlight:hover {
  box-shadow: 0 8px 28px rgba(66, 90, 239, 0.12);
  transform: translateY(-1px);
}

/* 顶部工具条：渐变底色 + 内边距 + 字体 */
.article-container .highlight-tools {
  background: linear-gradient(90deg, rgba(66, 90, 239, 0.04), rgba(139, 92, 246, 0.06), rgba(236, 72, 153, 0.04)) !important;
  padding: 0 1.2em !important;
  border-bottom: 1px solid var(--efu-card-border) !important;
  height: 2.6em !important;
  min-height: 2.6em !important;
}

/* 语言标签：药丸 + 主题色 */
.article-container .highlight-tools .code-lang {
  background: rgba(66, 90, 239, 0.1) !important;
  color: var(--efu-theme) !important;
  font-size: 0.75rem !important;
  font-weight: 700 !important;
  padding: 0.2em 0.7em !important;
  border-radius: 100px !important;
  border: 1px solid rgba(66, 90, 239, 0.2);
  letter-spacing: 0.3px;
  text-transform: lowercase !important;
  position: static !important;
  margin: 0 !important;
}

.article-container .highlight-tools .code-lang::before {
  content: "</> ";
  opacity: 0.7;
  margin-right: 2px;
}

/* 复制按钮：图标 + hover 动效 */
.article-container .highlight-tools .copy-button {
  color: var(--efu-secondtext) !important;
  font-size: 1rem !important;
  padding: 0.3rem;
  border-radius: 6px;
  transition: all 0.25s ease;
}

.article-container .highlight-tools .copy-button:hover {
  color: var(--efu-theme) !important;
  background: rgba(66, 90, 239, 0.1) !important;
  transform: scale(1.1);
}

/* 复制成功后：变绿 */
.article-container .highlight-tools.copy-true .copy-button {
  color: #10b981 !important;
}

.article-container .highlight-tools.copy-true .copy-button::after {
  content: "已复制";
  position: absolute;
  right: 0;
  top: 100%;
  margin-top: 4px;
  background: #10b981;
  color: #fff;
  font-size: 11px;
  padding: 2px 8px;
  border-radius: 4px;
  white-space: nowrap;
  font-style: normal;
}

/* 展开按钮 */
.article-container .highlight-tools .expand {
  color: var(--efu-secondtext) !important;
  font-size: 0.95rem !important;
  padding: 0.3rem;
  border-radius: 6px;
  transition: all 0.25s ease;
}

.article-container .highlight-tools .expand:hover {
  color: var(--efu-theme) !important;
  background: rgba(66, 90, 239, 0.1) !important;
}

.article-container .highlight-tools.closed .expand {
  transform: rotate(-90deg);
}

/* 代码区：内边距 + 字体 */
.article-container figure.highlight pre,
.article-container figure.highlight table,
.article-container pre {
  padding: 0 !important;
  margin: 0 !important;
}

.article-container figure.highlight .code pre,
.article-container figure.highlight .gutter pre {
  padding: 0.9em 1.1em !important;
  line-height: 1.7 !important;
  font-size: 14px;
  font-family: 'JetBrains Mono', Consolas, 'Fira Code', Menlo, monospace;
}

.article-container figure.highlight .gutter pre {
  color: var(--efu-secondtext) !important;
  user-select: none;
  border-right: 1px solid var(--efu-card-border) !important;
  background: rgba(0, 0, 0, 0.02) !important;
  text-align: right;
  min-width: 2.5em;
}

[data-theme="dark"] .article-container figure.highlight .gutter pre {
  background: rgba(255, 255, 255, 0.03) !important;
}

/* 横向溢出滚动条美化 */
.article-container figure.highlight pre::-webkit-scrollbar,
.article-container pre::-webkit-scrollbar {
  height: 6px;
}

.article-container figure.highlight pre::-webkit-scrollbar-thumb,
.article-container pre::-webkit-scrollbar-thumb {
  background: rgba(66, 90, 239, 0.3);
  border-radius: 3px;
}

.article-container figure.highlight pre::-webkit-scrollbar-thumb:hover,
.article-container pre::-webkit-scrollbar-thumb:hover {
  background: rgba(66, 90, 239, 0.55);
}

/* ============================================
 * ============ 4. TOC 目录美化 ============
 * ============================================ */

#card-toc {
  border-radius: 14px !important;
  border: 1px solid var(--efu-card-border);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.04);
  overflow: hidden;
  transition: box-shadow 0.3s ease;
}

#card-toc:hover {
  box-shadow: 0 6px 24px rgba(66, 90, 239, 0.1);
}

#card-toc .item-headline {
  border-bottom: 1px dashed var(--efu-card-border);
  padding: 0.6em 1em !important;
  font-weight: 700 !important;
  color: var(--efu-fontcolor) !important;
  background: linear-gradient(90deg, rgba(66, 90, 239, 0.05), transparent);
  display: flex !important;
  align-items: center;
}

#card-toc .item-headline i {
  color: var(--efu-theme);
  margin-right: 0.5em;
}

#card-toc .toc-content {
  padding: 0.5em 0.5em !important;
  max-height: 480px;
  overflow-y: auto;
}

#card-toc .toc-content::-webkit-scrollbar {
  width: 4px;
}

#card-toc .toc-content::-webkit-scrollbar-thumb {
  background: rgba(66, 90, 239, 0.25);
  border-radius: 2px;
}

#card-toc .toc-item .toc-link {
  padding: 0.4em 0.7em !important;
  border-radius: 6px !important;
  transition: all 0.2s ease;
  color: var(--efu-secondtext) !important;
  line-height: 1.5;
  border: none !important;
  font-weight: 500;
}

#card-toc .toc-item .toc-link:hover {
  color: var(--efu-theme) !important;
  background: rgba(66, 90, 239, 0.06);
  transform: translateX(2px);
}

#card-toc .toc-item.active > .toc-link {
  color: var(--efu-theme) !important;
  background: linear-gradient(90deg, rgba(66, 90, 239, 0.12), rgba(236, 72, 153, 0.04)) !important;
  font-weight: 700 !important;
  position: relative;
}

#card-toc .toc-item.active > .toc-link::before {
  content: "";
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 70%;
  background: linear-gradient(180deg, #425AEF, #8B5CF6, #EC4899);
  border-radius: 2px;
}

/* 子目录缩进 */
#card-toc .toc-child {
  border-left: 1px dashed var(--efu-card-border) !important;
  margin-left: 0.5em !important;
  padding-left: 0.3em !important;
}

/* ============================================
 * ============ 5. 分页器美化 ============
 * ============================================ */

#pagination .pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 0.5em;
  margin: 2em 0 !important;
}

#pagination .page-number,
#pagination .prev,
#pagination .next,
#pagination .space {
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  min-width: 2.4em;
  height: 2.4em;
  padding: 0 0.8em !important;
  border-radius: 10px !important;
  background: var(--efu-card-bg) !important;
  border: 1px solid var(--efu-card-border) !important;
  color: var(--efu-fontcolor) !important;
  font-weight: 600 !important;
  font-size: 0.9rem;
  transition: all 0.25s ease;
  text-decoration: none !important;
  cursor: pointer;
}

#pagination .page-number:hover,
#pagination .prev:hover,
#pagination .next:hover {
  transform: translateY(-2px);
  border-color: rgba(66, 90, 239, 0.4) !important;
  color: var(--efu-theme) !important;
  box-shadow: 0 4px 14px rgba(66, 90, 239, 0.15);
}

#pagination .page-number.current {
  background: linear-gradient(135deg, #425AEF, #8B5CF6) !important;
  color: #fff !important;
  border-color: transparent !important;
  box-shadow: 0 4px 14px rgba(66, 90, 239, 0.3);
  cursor: default;
}

#pagination .page-number.current:hover {
  transform: none;
}

/* 跳转页输入框 */
#pagination .toPageGroup input {
  border-radius: 8px !important;
  border: 1px solid var(--efu-card-border) !important;
  background: var(--efu-card-bg) !important;
  color: var(--efu-fontcolor) !important;
  padding: 0.3em 0.6em !important;
  width: 4em;
  text-align: center;
  transition: border-color 0.25s ease;
}

#pagination .toPageGroup input:focus {
  outline: none;
  border-color: var(--efu-theme) !important;
  box-shadow: 0 0 0 3px rgba(66, 90, 239, 0.1);
}

#pagination .toPageGroup a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 2.4em;
  height: 2.4em;
  border-radius: 10px !important;
  background: linear-gradient(135deg, #425AEF, #8B5CF6) !important;
  color: #fff !important;
  margin-left: 0.5em;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}

#pagination .toPageGroup a:hover {
  transform: translateY(-2px) scale(1.05);
  box-shadow: 0 4px 14px rgba(66, 90, 239, 0.3);
}

/* ============================================
 * ============ 6. 阅读进度条 ============
 * ============================================ */

#reading-progress {
  position: fixed;
  top: 0;
  left: 0;
  width: 0%;
  height: 3px;
  background: linear-gradient(90deg, #425AEF 0%, #8B5CF6 50%, #EC4899 100%);
  z-index: 9999;
  transition: width 0.1s linear;
  box-shadow: 0 0 8px rgba(139, 92, 246, 0.4);
  pointer-events: none;
}

/* ============================================
 * ============ 7. 侧边栏卡片微调 ============
 * ============================================ */

.aside-content .card-widget {
  border: 1px solid var(--efu-card-border);
  border-radius: 14px !important;
  overflow: hidden;
  transition: box-shadow 0.3s ease, transform 0.3s ease;
}

.aside-content .card-widget:hover {
