### 4.创建对应的生成器文件

``` javascript
import fs from 'node:fs'
import path from 'node:path'

function getFolder(path) {
  const components = []
  const files = fs.readdirSync(path)

  files.forEach((item) => {
    console.log('item',item)
    const stat = fs.lstatSync(`${path}/${item}`)
    if (stat.isDirectory() === true && item !== 'components') {
      components.push(`${path}/${item}`)
      components.push(...getFolder(`${path}/${item}`))
    }
  })
  return components
}

export default {
  description: '创建页面',
  prompts: [
    {
      type: 'list',
      name: 'path',
      message: '请选择页面创建目录',
      choices: getFolder('src/views'),
    },
    {
      type: 'input',
      name: 'name',
      message: '请输入文件名',
      validate: (v) => {
        if (!v || v.trim === '') {
          return '文件名不能为空'
        }
        else {
          return true
        }
      },
    },
    {
      type: 'confirm',
      name: 'isFilesystem',
      message: '是否为基于文件系统的路由页面',
      default: false,
    },
    {
      type: 'confirm', // 问题的类型
      name: 'hasDetail', // 问题对应得到答案的变量名，可以在actions中使用该变量
      message: '是否需要详情抽屉：', // 在命令行中的问题
      default: true // 问题的默认答案
    },
  ],
  actions: (data) => {
    const relativePath = path.relative('src/views', data.path)
    const actions = [
      {
        type: 'add', // 操作类型，这里是添加文件
        path: `${data.path}/{{dotCase name}}.vue`,// 模板生成的路径
        templateFile: 'plop-templates/page/index.hbs',
        data: {
          componentName: `${relativePath} ${data.name}`,
        },
      },

    ]
    if (data.hasDetail) {
      actions.push({
        type: 'add',
        path: `${data.path}/detail.vue`, // 模板生成的路径
        templateFile: 'plop-templates/page/detail.hbs', // 模板的路径
        data: {
          componentName: `${relativePath} ${data.name}`,
        },
      })
    }
    return actions
  },
}

```

