import fs from 'node:fs';
import path from 'node:path';

function getFolder(path) {
  const components = [];
  const files = fs.readdirSync(path);

  files.forEach((item) => {
    const stat = fs.lstatSync(`${path}/${item}`);
    if (stat.isDirectory() === true && item !== 'components') {
      components.push(`${path}/${item}`);
      components.push(...getFolder(`${path}/${item}`));
    }
  });
  return components;
}

export default {
  description: '创建页面',
  prompts: [
    {
      type: 'list',
      name: 'path',
      message: '请选择页面创建目录',
      choices: getFolder('src/views'),
    },
    {
      type: 'input',
      name: 'name',
      message: '请输入文件名',
      validate: (v) => {
        if (!v || v.trim() === '') {
          return '文件名不能为空';
        } else {
          return true;
        }
      },
    },
    {
      type: 'confirm',
      name: 'isFilesystem',
      message: '是否为基于文件系统的路由页面',
      default: false,
    },
    {
      type: 'confirm',
      name: 'hasDetail',
      message: '是否需要详情抽屉：',
      default: true,
    },
  ],
  actions: (data) => {
    const relativePath = path.relative('src/views', data.path);
    const actions = [
      {
        type: 'add',
        path: `${data.path}/{{dotCase name}}.vue`,
        templateFile: 'plop-templates/page/index.hbs',
        data: {
          componentName: `${relativePath} ${data.name}`,
        },
      },
    ];

    if (data.hasDetail) {
      actions.push({
        type: 'add',
        path: `${data.path}/detail.vue`,
        templateFile: 'plop-templates/page/detail.hbs',
        data: {
          componentName: `${relativePath} ${data.name}`,
        },
      });
    }

    // 添加 modify 操作
    actions.push({
      type: 'modify',
      path: 'src/router/index.js',
      pattern: /const routes = \[/,
      template: `const routes = [\n  $1  {\n    path: '/${data.name}',\n    name: '${data.name}',\n    component: () => import('../views/${relativePath}/${data.name}.vue'),\n  },`,
    });

    return actions;
  },
};
